import sys
from collections import deque
class Solution:
    def mostProfitablePath(self, edges, bob, amount):
        sys.setrecursionlimit(300000)
        n = len(amount)
        g = [[] for _ in range(n)]
        for a, b in edges:
            g[a].append(b)
            g[b].append(a)
        parent = [-1] * n
        seen = [False] * n
        dq = deque([0])
        seen[0] = True
        while dq:
            u = dq.popleft()
            for w in g[u]:
                if not seen[w]:
                    seen[w] = True
                    parent[w] = u
                    dq.append(w)
        bob_time = [float('inf')] * n
        cur, t = bob, 0
        while cur != -1:
            bob_time[cur] = t
            cur = parent[cur]
            t += 1
        best = [float('-inf')]
        def dfs(u, p, depth, income):
            if depth < bob_time[u]:
                income += amount[u]
            elif depth == bob_time[u]:
                income += amount[u] // 2
            leaf = True
            for w in g[u]:
                if w != p:
                    leaf = False
                    dfs(w, u, depth + 1, income)
            if leaf:
                if income > best[0]:
                    best[0] = income
        dfs(0, -1, 0, 0)
        return best[0]

