var mostProfitablePath = function(edges, bob, amount) {
    const n = amount.length;
    const g = Array.from({length: n}, () => []);
    for (const [a, b] of edges) { g[a].push(b); g[b].push(a); }
    const parent = new Array(n).fill(-1);
    const seen = new Array(n).fill(false);
    const q = [0]; seen[0] = true; let head = 0;
    while (head < q.length) {
        const u = q[head++];
        for (const w of g[u]) if (!seen[w]) { seen[w] = true; parent[w] = u; q.push(w); }
    }
    const bobTime = new Array(n).fill(Infinity);
    let cur = bob, t = 0;
    while (cur !== -1) { bobTime[cur] = t; cur = parent[cur]; t++; }
    let best = -Infinity;
    const stack = [[0, -1, 0, 0]];
    const incomeAt = (u, depth, income) => {
        if (depth < bobTime[u]) return income + amount[u];
        if (depth === bobTime[u]) return income + Math.trunc(amount[u] / 2);
        return income;
    };
    const dfs = (u, p, depth, income) => {
        income = incomeAt(u, depth, income);
        let leaf = true;
        for (const w of g[u]) if (w !== p) { leaf = false; dfs(w, u, depth + 1, income); }
        if (leaf && income > best) best = income;
    };
    dfs(0, -1, 0, 0);
    return best;
};
